import type { RudelClaudeSessionsRow, RudelSessionAnalyticsRow } from './chkit-types.js'
import { RudelClaudeSessionsRowSchema, RudelSessionAnalyticsRowSchema } from './chkit-types.js'

export interface Ingestor {
  insert(params: { table: string; values: Record<string, unknown>[] }): Promise<void>
}

export async function ingestRudelClaudeSessions(
  ingestor: Ingestor,
  rows: RudelClaudeSessionsRow[],
  options?: { validate?: boolean }
): Promise<void> {
  const data = options?.validate ? rows.map(row => RudelClaudeSessionsRowSchema.parse(row)) : rows
